import React, { useState, useEffect } from 'react';
import AgentWorkflow from '../components/AgentWorkflow';
import PatientCard from '../components/PatientCard';
import MetricsPanel from '../components/MetricsPanel';

const Dashboard = () => {
  const [paRequests, setPaRequests] = useState([]);
  const [activeDemo, setActiveDemo] = useState(null);

  useEffect(() => {
    // Fetch PA requests from backend
    fetchPARequests();
  }, []);

  const fetchPARequests = async () => {
    try {
      const response = await fetch('/api/pa-requests');
      const data = await response.json();
      setPaRequests(data);
    } catch (error) {
      console.log('Using demo data');
      // Use demo data if backend not available
      setPaRequests([
        {
          id: 'PA-2024-001',
          patientName: 'John Doe',
          procedure: 'Total Knee Arthroplasty',
          status: 'pending',
          priority: 'high'
        }
      ]);
    }
  };

  const startDemo = (requestId) => {
    setActiveDemo(requestId);
  };

  return (
    <div className="dashboard-container">
      <div className="dashboard-grid">
        <div className="left-panel">
          <PatientCard />
          <MetricsPanel />
        </div>
        
        <div className="center-panel">
          <AgentWorkflow activeDemo={activeDemo} />
        </div>

        <div className="right-panel">
          <div className="pa-queue">
            <h3>PA Request Queue</h3>
            {paRequests.map(request => (
              <div key={request.id} className="pa-request-card">
                <h4>{request.patientName}</h4>
                <p>{request.procedure}</p>
                <button onClick={() => startDemo(request.id)}>
                  Process PA
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
